#!/usr/bin/env python3
"""install_heatmap_v4.py — zone editor with 4-corner handles + SVG clip
Run from ~/Desktop/BatKnock:  python3 install_heatmap_v4.py
"""
import base64, os, sys
if not os.path.isdir("screens"): sys.exit("Run from BatKnock root")
PAYLOAD = ""
with open("screens/HeatmapScreen.js", "wb") as f:
    f.write(base64.b64decode(PAYLOAD))
print("✅ screens/HeatmapScreen.js updated")
print()
print("IMPORTANT — react-native-svg is already in your package.json.")
print("Run:  npx expo start --clear --lan")
print()
print("How to use:")
print("  1. Bat Profile → View Heatmap")
print("  2. Tap '✏️ Edit Zone Boundaries'")
print("  3. Drag the 4 WHITE circles to the 4 corners of your bat blade")
print("  4. Drag the BLUE line to set where the sweet spot begins")
print("  5. Drag the RED line to set where the toe begins")
print("  6. Tap 'Save Zone Boundaries'")
print("  7. The heatmap now renders only on the bat blade surface")
